mapper.update:
UPDATE ai_moderation_result
SET status = #{status},
    reviewed_by = #{adminId},
    reviewed_at = NOW()
WHERE target_type = #{targetType}
  AND target_id = #{targetId}

mapper.select:
SELECT id, target_type, target_id, author_id, risk_level, risk_types::text AS risk_types, confidence, reasons::text AS reasons, suggested_action, model_name, status, created_at, reviewed_by, reviewed_at FROM ai_moderation_result WHERE 1 = 1
AND target_type = #{targetType}
AND risk_level = #{riskLevel}
AND jsonb_exists(risk_types, #{riskType})
ORDER BY created_at DESC LIMIT #{limit} OFFSET #{offset}

SELECT COUNT(*)
FROM ai_moderation_result
WHERE 1 = 1

    AND target_type = #{targetType}


    AND risk_level = #{riskLevel}


    AND jsonb_exists(risk_types, #{riskType})
